import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"Custody and threat model","description":"","frontmatter":{},"headers":[],"relativePath":"internals/custody.md","filePath":"internals/custody.md"}'),s={name:"internals/custody.md"};function n(i,e,h,d,l,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="custody-and-threat-model" tabindex="-1">Custody and threat model <a class="header-anchor" href="#custody-and-threat-model" aria-label="Permalink to &quot;Custody and threat model&quot;">​</a></h1><p>New-user onboarding is non-custodial end to end. No private key ever leaves the browser. This page is honest about what that means, including the limits.</p><h2 id="the-bootstrap-key" tabindex="-1">The bootstrap key <a class="header-anchor" href="#the-bootstrap-key" aria-label="Permalink to &quot;The bootstrap key&quot;">​</a></h2><p>EIP-7702 needs a secp256k1 signature to authorize the delegation and the first passkey. The browser generates a one-time bootstrap key for that.</p><p>The key is generated in a function closure. It signs exactly two things: the 7702 authorization and the EIP-712 digest that binds the first passkey. Then every reference to it is dropped.</p><ul><li>It is never placed in application state.</li><li>It is never rendered or logged.</li><li>It is never written to storage of any kind.</li><li>It is never sent over the network. Only the signatures travel.</li></ul><p>The guardian relays one transaction and pays its gas. A request-body check rejects anything key-shaped on every endpoint, before any handler runs.</p><h2 id="the-7702-root-key-note" tabindex="-1">The 7702 root-key note <a class="header-anchor" href="#the-7702-root-key-note" aria-label="Permalink to &quot;The 7702 root-key note&quot;">​</a></h2><p>Be honest about the design. By EIP-7702&#39;s rules, the secp256k1 key remains the theoretical root authority of the address. Ours is generated in the tab, used once, and garbage collected. It is unrecoverable and un-persisted, by us or by anyone.</p><p>The practical threat model is the browser session during those milliseconds of signing. After that, key compromise is impossible, because the key no longer exists. Recovery from then on runs through Arise&#39;s purpose-bound single-use codes while the testnet issuer operates.</p><h2 id="after-onboarding" tabindex="-1">After onboarding <a class="header-anchor" href="#after-onboarding" aria-label="Permalink to &quot;After onboarding&quot;">​</a></h2><p>The passkey is the sole practical authority. Every operation is passkey-signed. The guardian is a relayer. The contracts enforce this, and the fork tests prove a malicious relayer cannot tamper, replay, or redirect a signed batch.</p><h2 id="the-legacy-demo-path" tabindex="-1">The legacy demo path <a class="header-anchor" href="#the-legacy-demo-path" aria-label="Permalink to &quot;The legacy demo path&quot;">​</a></h2><p>The alice account predates this flow. The guardian held its key for the original one-time upgrade, and for its final legacy use, the v1 to v2 re-delegation. The app labels this path as legacy.</p><h2 id="existing-wallets" tabindex="-1">Existing wallets <a class="header-anchor" href="#existing-wallets" aria-label="Permalink to &quot;Existing wallets&quot;">​</a></h2><p>Upgrading an existing wallet, where a user delegates their own Rabby or MetaMask account, is pending wallet-side EIP-7702 authorization support. This is stated, not promised.</p>',16)])])}const y=t(s,[["render",n]]);export{u as __pageData,y as default};
